## Objective
Implement password and public key authentication handlers with pluggable authentication backends.

## Implementation Details

### Authentication Trait
```rust
use async_trait::async_trait;

#[async_trait]
pub trait Authenticator: Send + Sync {
    /// Authenticate with username and password
    async fn auth_password(&self, user: &str, password: &str) -> AuthResult;

    /// Authenticate with public key
    async fn auth_publickey(&self, user: &str, key: &PublicKey) -> AuthResult;

    /// Check if authentication method is supported
    fn supports_method(&self, method: AuthMethod) -> bool;
}

pub enum AuthResult {
    Accept,
    Reject,
    Partial { remaining_methods: Vec<AuthMethod> },
}

pub enum AuthMethod {
    Password,
    PublicKey,
    KeyboardInteractive,
}
```

